import{_ as e,c as o,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Perguntas Frequentes: Autenticação OAuth e Solução de Problemas de Modelo | Antigravity Auth","description":"Entenda as perguntas frequentes e soluções do plugin Antigravity Auth. Abrange a solução de problemas de falhas de autenticação OAuth, tratamento de erros de modelo não encontrado, configuração de compatibilidade de plugins e outros guias práticos para ajudá-lo a localizar e resolver rapidamente vários problemas encontrados durante o uso.","frontmatter":{"title":"Perguntas Frequentes: Autenticação OAuth e Solução de Problemas de Modelo | Antigravity Auth","sidebarTitle":"O que fazer quando a autenticação falha","subtitle":"Perguntas Frequentes: Autenticação OAuth e Solução de Problemas de Modelo","description":"Entenda as perguntas frequentes e soluções do plugin Antigravity Auth. Abrange a solução de problemas de falhas de autenticação OAuth, tratamento de erros de modelo não encontrado, configuração de compatibilidade de plugins e outros guias práticos para ajudá-lo a localizar e resolver rapidamente vários problemas encontrados durante o uso.","order":4},"headers":[],"relativePath":"pt/NoeFabris/opencode-antigravity-auth/faq/index.md","filePath":"pt/NoeFabris/opencode-antigravity-auth/faq/index.md"}'),r={name:"pt/NoeFabris/opencode-antigravity-auth/faq/index.md"};function d(n,a,s,l,u,c){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="perguntas-frequentes" tabindex="-1">Perguntas Frequentes <a class="header-anchor" href="#perguntas-frequentes" aria-label="Permalink to &quot;Perguntas Frequentes&quot;">​</a></h1><p>Este capítulo coleta os problemas mais comuns encontrados ao usar o plugin Antigravity Auth e suas soluções. Seja falha na autenticação OAuth, erros de solicitação de modelo ou problemas de compatibilidade de plugins, aqui há guias de solução de problemas correspondentes.</p><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de começar, certifique-se</p><ul><li>✅ Já completou a <a href="./../start/quick-install/">Instalação Rápida</a> e adicionou contas com sucesso</li><li>✅ Já completou a <a href="./../start/first-auth-login/">Primeira Autenticação</a> e entende o fluxo OAuth</li></ul></div><h2 id="caminho-de-aprendizado" tabindex="-1">Caminho de Aprendizado <a class="header-anchor" href="#caminho-de-aprendizado" aria-label="Permalink to &quot;Caminho de Aprendizado&quot;">​</a></h2><p>Escolha o guia de solução de problemas correspondente com base no tipo de problema que você está enfrentando:</p><h3 id="_1-solucao-de-problemas-de-falha-na-autenticacao-oauth" tabindex="-1">1. <a href="./common-auth-issues/">Solução de Problemas de Falha na Autenticação OAuth</a> <a class="header-anchor" href="#_1-solucao-de-problemas-de-falha-na-autenticacao-oauth" aria-label="Permalink to &quot;1. [Solução de Problemas de Falha na Autenticação OAuth](./common-auth-issues/)&quot;">​</a></h3><p>Resolva problemas comuns relacionados à autenticação OAuth, atualização de tokens e contas.</p><ul><li>Autorização no navegador bem-sucedida, mas o terminal exibe &quot;Falha na autorização&quot;</li><li>Repentinamente exibe erro &quot;Permission Denied&quot; ou &quot;invalid_grant&quot;</li><li>Falha no callback OAuth do navegador Safari</li><li>Não é possível completar a autenticação no ambiente WSL2/Docker</li></ul><h3 id="_2-migracao-de-conta" tabindex="-1">2. <a href="./migration-guide/">Migração de Conta</a> <a class="header-anchor" href="#_2-migracao-de-conta" aria-label="Permalink to &quot;2. [Migração de Conta](./migration-guide/)&quot;">​</a></h3><p>Migre contas entre diferentes máquinas e gerencie atualizações de versão.</p><ul><li>Migrar contas do computador antigo para o novo</li><li>Entender as mudanças de versão do formato de armazenamento (v1/v2/v3)</li><li>Resolver erros de invalid_grant após a migração</li></ul><h3 id="_3-solucao-de-problemas-de-modelo-nao-encontrado" tabindex="-1">3. <a href="./model-not-found/">Solução de Problemas de Modelo Não Encontrado</a> <a class="header-anchor" href="#_3-solucao-de-problemas-de-modelo-nao-encontrado" aria-label="Permalink to &quot;3. [Solução de Problemas de Modelo Não Encontrado](./model-not-found/)&quot;">​</a></h3><p>Resolva problemas relacionados a modelo não encontrado, erros 400, etc.</p><ul><li>Solução de problemas de erro <code>Model not found</code></li><li>Erro 400 <code>Invalid JSON payload received. Unknown name &quot;parameters&quot;</code></li><li>Erro ao chamar servidor MCP</li></ul><h3 id="_4-compatibilidade-de-plugin" tabindex="-1">4. <a href="./plugin-compatibility/">Compatibilidade de Plugin</a> <a class="header-anchor" href="#_4-compatibilidade-de-plugin" aria-label="Permalink to &quot;4. [Compatibilidade de Plugin](./plugin-compatibility/)&quot;">​</a></h3><p>Resolva problemas de compatibilidade com plugins como oh-my-opencode, DCP, etc.</p><ul><li>Configure corretamente a ordem de carregamento de plugins</li><li>Desabilite métodos de autenticação conflitantes no oh-my-opencode</li><li>Ative deslocamento de PID para cenários de agentes paralelos</li></ul><h3 id="_5-aviso-de-tos" tabindex="-1">5. <a href="./tos-warning/">Aviso de ToS</a> <a class="header-anchor" href="#_5-aviso-de-tos" aria-label="Permalink to &quot;5. [Aviso de ToS](./tos-warning/)&quot;">​</a></h3><p>Entenda os riscos de uso e evite o bloqueio de contas.</p><ul><li>Entenda as restrições dos Termos de Serviço do Google</li><li>Identifique cenários de alto risco (novas contas, solicitações intensivas)</li><li>Domine as práticas recomendadas para evitar o bloqueio de contas</li></ul><h2 id="localizacao-rapida-de-problemas" tabindex="-1">Localização Rápida de Problemas <a class="header-anchor" href="#localizacao-rapida-de-problemas" aria-label="Permalink to &quot;Localização Rápida de Problemas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fenômeno de erro</th><th>Leitura recomendada</th></tr></thead><tbody><tr><td>Falha na autenticação, tempo limite de autorização</td><td><a href="./common-auth-issues/">Solução de Problemas de Falha na Autenticação OAuth</a></td></tr><tr><td>invalid_grant, Permission Denied</td><td><a href="./common-auth-issues/">Solução de Problemas de Falha na Autenticação OAuth</a></td></tr><tr><td>Model not found, erro 400</td><td><a href="./model-not-found/">Solução de Problemas de Modelo Não Encontrado</a></td></tr><tr><td>Conflito com outros plugins</td><td><a href="./plugin-compatibility/">Compatibilidade de Plugin</a></td></tr><tr><td>Trocar para novo computador, atualização de versão</td><td><a href="./migration-guide/">Migração de Conta</a></td></tr><tr><td>Preocupado com segurança da conta</td><td><a href="./tos-warning/">Aviso de ToS</a></td></tr></tbody></table><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Depois de resolver os problemas, você pode:</p><ul><li>📖 Ler <a href="./../advanced/">Funcionalidades Avançadas</a> para dominar profundamente recursos como múltiplas contas, recuperação de sessão, etc.</li><li>📚 Consultar <a href="./../appendix/">Apêndice</a> para entender design de arquitetura e referência de configuração completa</li><li>🔄 Acompanhar <a href="./../changelog/">Registro de Alterações</a> para obter as funcionalidades mais recentes e alterações</li></ul>',26)])])}const h=e(r,[["render",d]]);export{p as __pageData,h as default};
